package graph

import (
	"fmt"

	apiv1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/types"
	"k8s.io/apimachinery/pkg/util/validation/field"
	gatewayv1 "sigs.k8s.io/gateway-api/apis/v1"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/conditions"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kinds"
)

func buildTLSRoute(
	gtr *gatewayv1.TLSRoute,
	gws map[types.NamespacedName]*Gateway,
	services map[types.NamespacedName]*apiv1.Service,
	backendTLSPolicies map[types.NamespacedName]*BackendTLSPolicy,
	refGrantResolver func(resource toResource) bool,
	listenerSets map[types.NamespacedName]*ListenerSet,
) *L4Route {
	r := &L4Route{
		Source:    gtr,
		RouteType: RouteTypeTLS,
	}

	sectionNameRefs, err := buildSectionNameRefs(gtr.Spec.ParentRefs, gtr.Namespace, gws, listenerSets)
	if err != nil {
		r.Valid = false

		return r
	}
	// route doesn't belong to any of the Gateways or ListenerSets
	if len(sectionNameRefs) == 0 {
		return nil
	}
	r.ParentRefs = sectionNameRefs

	if err := validateHostnames(
		gtr.Spec.Hostnames,
		field.NewPath("spec").Child("hostnames"),
	); err != nil {
		r.Valid = false
		condMsg := helpers.CapitalizeString(err.Error())
		r.Conditions = append(r.Conditions, conditions.NewRouteUnsupportedValue(condMsg))
		return r
	}

	r.Spec.Hostnames = gtr.Spec.Hostnames

	if len(gtr.Spec.Rules) != 1 || len(gtr.Spec.Rules[0].BackendRefs) != 1 {
		r.Valid = false
		cond := conditions.NewRouteBackendRefUnsupportedValue(
			"Must have exactly one Rule and BackendRef",
		)
		r.Conditions = append(r.Conditions, cond)
		return r
	}

	tlsTerminateMode := hasTLSTerminateParent(sectionNameRefs, gws, listenerSets)
	br, conds := validateBackendRefTLSRoute(gtr, services, backendTLSPolicies, tlsTerminateMode, refGrantResolver)

	r.Spec.BackendRef = br
	r.Valid = true
	r.Attachable = true

	if len(conds) > 0 {
		r.Conditions = append(r.Conditions, conds...)
	}

	return r
}

func validateBackendRefTLSRoute(
	gtr *gatewayv1.TLSRoute,
	services map[types.NamespacedName]*apiv1.Service,
	backendTLSPolicies map[types.NamespacedName]*BackendTLSPolicy,
	tlsTerminateMode bool,
	refGrantResolver func(resource toResource) bool,
) (BackendRef, []conditions.Condition) {
	// Length of BackendRefs and Rules is guaranteed to be one due to earlier check in buildTLSRoute
	refPath := field.NewPath("spec").Child("rules").Index(0).Child("backendRefs").Index(0)

	ref := gtr.Spec.Rules[0].BackendRefs[0]

	if valid, cond := validateBackendRef(
		ref,
		gtr.Namespace,
		refGrantResolver,
		refPath,
	); !valid {
		backendRef := BackendRef{
			Valid:              false,
			InvalidForGateways: make(map[types.NamespacedName]conditions.Condition),
		}

		return backendRef, []conditions.Condition{cond}
	}

	ns := gtr.Namespace
	if ref.Namespace != nil {
		ns = string(*ref.Namespace)
	}

	svcNsName := types.NamespacedName{
		Namespace: ns,
		Name:      string(gtr.Spec.Rules[0].BackendRefs[0].Name),
	}

	svcPort, err := getPortFromRef(
		ref,
		svcNsName,
		services,
		refPath,
	)

	backendRef := BackendRef{
		SvcNsName:          svcNsName,
		ServicePort:        svcPort,
		Valid:              true,
		InvalidForGateways: make(map[types.NamespacedName]conditions.Condition),
	}

	if err != nil {
		backendRef.Valid = false

		return backendRef, []conditions.Condition{conditions.NewRouteBackendRefRefBackendNotFound(err.Error())}
	}

	backendTLSPolicy, err := findBackendTLSPolicyForService(
		backendTLSPolicies,
		ref.Namespace,
		string(ref.Name),
		gtr.Namespace,
		svcPort,
	)
	backendRef.BackendTLSPolicy = backendTLSPolicy
	if err != nil {
		backendRef.Valid = false

		return backendRef, []conditions.Condition{conditions.NewRouteBackendRefUnsupportedValue(err.Error())}
	}

	if svcPort.AppProtocol != nil {
		err = validateRouteBackendRefAppProtocol(RouteTypeTLS, *svcPort.AppProtocol, backendTLSPolicy)
		if err == nil &&
			tlsTerminateMode &&
			*svcPort.AppProtocol == AppProtocolTypeWSS &&
			backendTLSPolicy == nil {
			//nolint: staticcheck // used in status condition which is normally capitalized
			err = fmt.Errorf(
				"The Route type %s does not support service port appProtocol %s; missing corresponding BackendTLSPolicy",
				RouteTypeTLS,
				*svcPort.AppProtocol,
			)
		}
		if err != nil {
			backendRef.Valid = false

			return backendRef, []conditions.Condition{conditions.NewRouteBackendRefUnsupportedProtocol(err.Error())}
		}
	}

	return backendRef, nil
}

func hasTLSTerminateParent(
	parentRefs []ParentRef,
	gws map[types.NamespacedName]*Gateway,
	listenerSets map[types.NamespacedName]*ListenerSet,
) bool {
	for _, parentRef := range parentRefs {
		switch parentRef.Kind {
		case kinds.Gateway:
			gw, exists := gws[parentRef.NamespacedName]
			if !exists || gw == nil {
				continue
			}
			if hasTLSTerminateListener(gw.Listeners, parentRef.SectionName) {
				return true
			}
		case kinds.ListenerSet:
			ls, exists := listenerSets[parentRef.NamespacedName]
			if !exists || ls == nil {
				continue
			}
			if hasTLSTerminateListener(ls.Listeners, parentRef.SectionName) {
				return true
			}
		}
	}

	return false
}

func hasTLSTerminateListener(listeners []*Listener, sectionName *gatewayv1.SectionName) bool {
	for _, listener := range listeners {
		if listener == nil || listener.Source.Protocol != gatewayv1.TLSProtocolType {
			continue
		}

		if sectionName != nil && listener.Name != string(*sectionName) {
			continue
		}

		if listener.Source.TLS != nil &&
			(listener.Source.TLS.Mode == nil || *listener.Source.TLS.Mode == gatewayv1.TLSModeTerminate) {
			return true
		}
	}

	return false
}

package graph

import (
	apiv1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/types"
	"sigs.k8s.io/gateway-api/apis/v1alpha2"
)

func buildTCPRoute(
	tcpRoute *v1alpha2.TCPRoute,
	gws map[types.NamespacedName]*Gateway,
	services map[types.NamespacedName]*apiv1.Service,
	refGrantResolver func(resource toResource) bool,
	listenerSets map[types.NamespacedName]*ListenerSet,
) *L4Route {
	// Convert TCPRoute rules to generic l4RouteRule format
	rules := make([]l4RouteRule, len(tcpRoute.Spec.Rules))
	for i, rule := range tcpRoute.Spec.Rules {
		rules[i] = l4RouteRule{
			backendRefs: rule.BackendRefs,
		}
	}

	// Use the generic L4 route builder
	config := l4RouteConfig{
		source:           tcpRoute,
		namespace:        tcpRoute.Namespace,
		parentRefs:       tcpRoute.Spec.ParentRefs,
		rules:            rules,
		routeType:        RouteTypeTCP,
		refGrantResolver: refGrantResolver,
	}

	return buildGenericL4Route(config, gws, services, listenerSets)
}

package graph

import (
	apiv1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/types"
	"sigs.k8s.io/gateway-api/apis/v1alpha2"
)

func buildUDPRoute(
	udpRoute *v1alpha2.UDPRoute,
	gws map[types.NamespacedName]*Gateway,
	services map[types.NamespacedName]*apiv1.Service,
	refGrantResolver func(resource toResource) bool,
	listenerSets map[types.NamespacedName]*ListenerSet,
) *L4Route {
	// Convert UDPRoute rules to generic l4RouteRule format
	rules := make([]l4RouteRule, len(udpRoute.Spec.Rules))
	for i, rule := range udpRoute.Spec.Rules {
		rules[i] = l4RouteRule{
			backendRefs: rule.BackendRefs,
		}
	}

	// Use the generic L4 route builder
	config := l4RouteConfig{
		source:           udpRoute,
		namespace:        udpRoute.Namespace,
		parentRefs:       udpRoute.Spec.ParentRefs,
		rules:            rules,
		routeType:        RouteTypeUDP,
		refGrantResolver: refGrantResolver,
	}

	return buildGenericL4Route(config, gws, services, listenerSets)
}

package graph

import (
	"fmt"

	"k8s.io/apimachinery/pkg/types"
	"k8s.io/apimachinery/pkg/util/validation/field"
	"sigs.k8s.io/controller-runtime/pkg/client"
	v1 "sigs.k8s.io/gateway-api/apis/v1"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/config"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/conditions"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/resolver"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/controller"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kinds"
)

// Gateway represents a Gateway resource.
type Gateway struct {
	// LatestReloadResult is the result of the last nginx reload attempt.
	LatestReloadResult NginxReloadResult
	// AttachedListenerSets contains the ListenerSets that are attached and accepted by this Gateway.
	AttachedListenerSets map[types.NamespacedName]*ListenerSet
	// Source is the corresponding Gateway resource.
	Source *v1.Gateway
	// NginxProxy is the NginxProxy referenced by this Gateway.
	NginxProxy *NginxProxy
	// EffectiveNginxProxy holds the result of merging the NginxProxySpec on this resource with the NginxProxySpec on
	// the GatewayClass resource. This is the effective set of config that should be applied to the Gateway.
	// If non-nil, then this config is valid.
	EffectiveNginxProxy *EffectiveNginxProxy
	// SecretRef is the namespaced name of the secret referenced by the Gateway for backend TLS.
	SecretRef *types.NamespacedName
	// ListenerNamespaces holds the allowed listener namespaces for this Gateway, if specified.
	ListenerNamespaces *v1.ListenerNamespaces
	// ListenerFactory is used to create listeners for this Gateway. This is used to validate
	// listeners when they are created by the Gateway's Listeners, or merged via ListenerSets.
	ListenerFactory *listenerConfiguratorFactory
	// DeploymentName is the name of the nginx Deployment associated with this Gateway.
	DeploymentName types.NamespacedName
	// Listeners include the listeners of the Gateway.
	Listeners []*Listener
	// Conditions holds the conditions for the Gateway.
	Conditions []conditions.Condition
	// Policies holds the policies attached to the Gateway.
	Policies []*Policy
	// Valid indicates whether the Gateway Spec is valid.
	Valid bool
}

// processGateways determines which Gateway resources belong to NGF (determined by the Gateway GatewayClassName field).
func processGateways(
	gws map[types.NamespacedName]*v1.Gateway,
	gcName string,
) map[types.NamespacedName]*v1.Gateway {
	referencedGws := make(map[types.NamespacedName]*v1.Gateway)

	for gwNsName, gw := range gws {
		if string(gw.Spec.GatewayClassName) != gcName {

				NginxProxy:          np,
				EffectiveNginxProxy: effectiveNginxProxy,
				Conditions:          conds,
				DeploymentName:      deploymentName,
				SecretRef:           secretRefNsName,
				ListenerNamespaces:  listenerNamespaces,
			}
		} else {
			gateway := &Gateway{
				Source:              gw,
				NginxProxy:          np,
				EffectiveNginxProxy: effectiveNginxProxy,
				Valid:               true,
				Conditions:          conds,
				DeploymentName:      deploymentName,
				SecretRef:           secretRefNsName,
				ListenerNamespaces:  listenerNamespaces,
				ListenerFactory:     newListenerConfiguratorFactory(gw, resourceResolver, refGrantResolver, protectedPorts),
			}
			gateway.Listeners = buildListeners(gateway, gw.Spec.Listeners, gwNsName, types.NamespacedName{})
			builtGateways[gwNsName] = gateway
		}
	}

	return builtGateways
}

// validateGatewayRefs validates both parametersRef and TLS fields.
func validateGatewayRefs(
	gw *v1.Gateway,
	npCfg *NginxProxy,
	resourceResolver resolver.Resolver,
	refGrantResolver *referenceGrantResolver,
) ([]conditions.Condition, *types.NamespacedName) {
	if (gw.Spec.Infrastructure == nil || gw.Spec.Infrastructure.ParametersRef == nil) &&
